const observers = new Map();

export function initialize(sentinelElement, dotNetHelper) {
    if (observers.has(sentinelElement)) {
        return;
    }

    const observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetHelper.invokeMethodAsync("OnSentinelVisible");
            }
        }
    }, { rootMargin: "250px" });

    observer.observe(sentinelElement);
    observers.set(sentinelElement, observer);
}

export function dispose(sentinelElement) {
    const observer = observers.get(sentinelElement);
    if (observer) {
        observer.disconnect();
        observers.delete(sentinelElement);
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="d-flex justify-content-center py-3">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;
    private bool _initialized;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infiniteScroll.js");
        }

        if (HasMore && _module is not null)
        {
            await _module.InvokeVoidAsync("initialize", _sentinelRef, _dotNetRef);
            _initialized = true;
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            if (_initialized)
            {
                try
                {
                    await _module.InvokeVoidAsync("dispose", _sentinelRef);
                }
                catch (JSDisconnectedException)
                {
                    // Circuit already gone — nothing to clean up on the client.
                }
            }
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

